// SRE AIOps Parser v9 — Direct Insert Mode
// Each walker sends directly to this parser. Insert immediately per walker type.
// ═══════════════════════════════════════════════════════════════════════════════

const pool = global.get("pgPool");
if (!pool) { node.error("pgPool not available"); return null; }

try {
    if (!msg.payload || !Array.isArray(msg.payload)) return null;
    const flatData = msg.payload.flat();
    const walkerType = msg._walker || 'unknown';
    const deviceId = sanitize(msg.topic || '');
    if (!deviceId) return null;

    const parsed = parseAll(flatData);
    const queries = [];

    if (walkerType === 'cpu' || walkerType === 'storage') {
        queries.push(buildSysQuery([{
            device_id: deviceId,
            cpu_cores: parsed.cpu.coreCount,
            cpu_load_percent: parsed.cpu.loadPercent,
            ram_total_mb: parsed.disk.ramTotalMb,
            ram_used_mb: parsed.disk.ramUsedMb,
            ram_free_mb: parsed.disk.ramFreeMb,
            disk_total_gb: parsed.disk.totalGb,
            disk_used_gb: parsed.disk.usedGb,
            disk_free_gb: parsed.disk.freeGb,
            disk_description: JSON.stringify(parsed.disk.descriptions),
            temp_c: parsed.temp
        }]));
    }

    if (walkerType === 'net') {
        const netRate = calcNetRate(deviceId, parsed.ifaces);
        if (netRate.length > 0) {
            queries.push(buildNetQuery(netRate.map(iface => ({
                device_id: deviceId,
                iface_name: iface.name,
                rx_mbps: iface.rxMbps,
                tx_mbps: iface.txMbps,
                rx_errors: iface.rxErrors,
                tx_errors: iface.txErrors,
                rx_drops: iface.rxDrops,
                tx_drops: iface.txDrops,
                status: iface.status
            }))));
        }
    }

    if (walkerType === 'ldi') {
        queries.push(buildLdiQuery([{
            device_id: deviceId,
            throughput: parsed.ldi.throughput,
            temperature: parsed.ldi.temp,
            humidity: parsed.ldi.humidity,
            pressure: parsed.ldi.pressure,
            joule_effect: parsed.ldi.je,
            power_watt: parsed.ldi.power,
            vibration: parsed.ldi.vibration
        }]));
    }

    for (const q of queries) {
        pool.query(q.sql, q.params, function(err) {
            if (err) node.error('INSERT [' + q.name + '] failed: ' + err.message);
            else node.log('INSERT [' + q.name + '] ok: ' + q.count + ' rows');
        });
    }
    return null;
