// SQL Builders — hardcoded column lists, explicit $N placeholders
// ═══════════════════════════════════════════════════════════════════════════════

function buildSysQuery(rows) {
    const ph = rows.map((_, i) => {
        const b = i * 11;
        return `(NOW(),$${b+1},$${b+2},$${b+3},$${b+4},$${b+5},$${b+6},$${b+7},$${b+8},$${b+9},$${b+10},$${b+11})`;
    }).join(',');
    const params = [];
    for (const r of rows) params.push(r.device_id, r.cpu_cores, r.cpu_load_percent, r.ram_total_mb, r.ram_used_mb, r.ram_free_mb, r.disk_total_gb, r.disk_used_gb, r.disk_free_gb, r.disk_description, r.temp_c);
    return { name: 'sys', count: rows.length,
        sql: 'INSERT INTO public.sys_metrics ("time",device_id,cpu_cores,cpu_load_percent,ram_total_mb,ram_used_mb,ram_free_mb,disk_total_gb,disk_used_gb,disk_free_gb,disk_description,temp_c) VALUES ' + ph,
        params: params };
}

function buildNetQuery(rows) {
    const ph = rows.map((_, i) => {
        const b = i * 9;
        return `(NOW(),$${b+1},$${b+2},$${b+3},$${b+4},$${b+5},$${b+6},$${b+7},$${b+8},$${b+9})`;
    }).join(',');
    const params = [];
    for (const r of rows) params.push(r.device_id, r.iface_name, r.rx_mbps, r.tx_mbps, r.rx_errors, r.tx_errors, r.rx_drops, r.tx_drops, r.status);
    return { name: 'net', count: rows.length,
        sql: 'INSERT INTO public.net_metrics ("time",device_id,iface_name,rx_mbps,tx_mbps,rx_errors,tx_errors,rx_drops,tx_drops,status) VALUES ' + ph,
        params: params };
}

function buildLdiQuery(rows) {
    const ph = rows.map((_, i) => {
        const b = i * 8;
        return `(NOW(),$${b+1},$${b+2},$${b+3},$${b+4},$${b+5},$${b+6},$${b+7},$${b+8})`;
    }).join(',');
    const params = [];
    for (const r of rows) params.push(r.device_id, r.throughput, r.temperature, r.humidity, r.pressure, r.joule_effect, r.power_watt, r.vibration);
    return { name: 'ldi', count: rows.length,
        sql: 'INSERT INTO public.ldi_metrics ("time",device_id,throughput,temperature,humidity,pressure,joule_effect,power_watt,vibration) VALUES ' + ph,
        params: params };
}


// ═══════════════════════════════════════════════════════════════════════════════
// Parser Functions
// ═══════════════════════════════════════════════════════════════════════════════

function sanitize(s) { return s.replace(/[^a-zA-Z0-9_\-\.]/g, ''); }
function mkIface(idx) { return { name: '', status: 0, rx32: 0, tx32: 0, rx64: 0, tx64: 0, err: 0, drop: 0 }; }

function parseAll(items) {
    const cpu = { total: 0, count: 0 };
    let maxTemp = 0;
    const storageEntries = {};
    const ifaces = {};
    const ldi = { throughput: 0, temp: 0, humidity: 0, pe: 0, je: 0, power: 0, vibration: 0 };
    const LDI_MAP = { '1.3.6.1.4.1.9999.1.1.0': 'throughput', '1.3.6.1.4.1.9999.1.2.0': 'temp', '1.3.6.1.4.1.9999.1.3.0': 'humidity', '1.3.6.1.4.1.9999.1.4.2': 'pe', '1.3.6.1.4.1.9999.1.5.1': 'je', '1.3.6.1.4.1.9999.1.6.1': 'power', '1.3.6.1.4.1.9999.1.7.1': 'vibration' };

    for (const item of items) {
        const oid = item.oid, val = item.value;
        const cpuMatch = oid.match(/1\.3\.6\.1\.2\.1\.25\.3\.3\.1\.2\.(\d+)$/);
        if (cpuMatch) { const n = Number(val) || 0; if (n > 0) { cpu.total += n; cpu.count++; } }
        const stoMatch = oid.match(/1\.3\.6\.1\.2\.1\.25\.2\.3\.1\.(\d+)\.(\d+)$/);
        if (stoMatch) {
            const [, prop, idx] = stoMatch;
            if (!storageEntries[idx]) storageEntries[idx] = {};
            if (prop === '2') storageEntries[idx].type = String(val);
            if (prop === '3') storageEntries[idx].desc = String(val);
            if (prop === '4') storageEntries[idx].au = Number(val) || 0;
            if (prop === '5') storageEntries[idx].size = Number(val) || 0;
            if (prop === '6') storageEntries[idx].used = Number(val) || 0;
        }
        const ifMatch = oid.match(/1\.3\.6\.1\.2\.1\.2\.2\.1\.(\d+)\.(\d+)$/);
        if (ifMatch) {
            const [, prop, idx] = ifMatch;
            if (!ifaces[idx]) ifaces[idx] = mkIface(idx);
            if (prop === '2') ifaces[idx].name = String(val);
            if (prop === '8') ifaces[idx].status = Number(val);
            if (prop === '10') ifaces[idx].rx32 = Number(val) || 0;
            if (prop === '13') ifaces[idx].drop += Number(val) || 0;
            if (prop === '14') ifaces[idx].err += Number(val) || 0;
            if (prop === '16') ifaces[idx].tx32 = Number(val) || 0;
        }
        const xMatch = oid.match(/1\.3\.6\.1\.2\.1\.31\.1\.1\.1\.(\d+)\.(\d+)$/);
        if (xMatch) {
            const [, prop, idx] = xMatch;
            if (!ifaces[idx]) ifaces[idx] = mkIface(idx);
            if (prop === '10') ifaces[idx].tx64 = Number(val) || 0;
            if (prop === '6') ifaces[idx].rx64 = Number(val) || 0;
        }
        const tempMatch = oid.match(/1\.3\.6\.1\.4\.1\.2021\.13\.16\.2\.1\.7\.(\d+)$/);
        if (tempMatch) { const t = Number(val) || 0; if (t > maxTemp) maxTemp = t; }
        if (LDI_MAP[oid]) { ldi[LDI_MAP[oid]] = Number(val) || 0; }
    }
    const avgCpu = cpu.count > 0 ? cpu.total / cpu.count : 0;
    return { cpu: { loadPercent: avgCpu, coreCount: cpu.count }, temp: maxTemp, disk: calcDisk(storageEntries), ifaces, ldi };
}

function calcDisk(entries) {
    let ramTotalMb = 0, ramUsedMb = 0, ramFreeMb = 0, totalGb = 0, usedGb = 0, freeGb = 0;
    const descriptions = [];
    for (const idx of Object.keys(entries).sort()) {
        const e = entries[idx];
        if (e.type && e.type.includes('1.3.6.1.2.1.25.2.1.2')) {
            ramTotalMb = (e.size * e.au) / (1024 * 1024);
            ramUsedMb = (e.used * e.au) / (1024 * 1024);
            ramFreeMb = ramTotalMb - ramUsedMb;
        } else if (e.type && e.type.includes('1.3.6.1.2.1.25.2.1.4')) {
            totalGb = (e.size * e.au) / (1024 * 1024 * 1024);
            usedGb = (e.used * e.au) / (1024 * 1024 * 1024);
            freeGb = totalGb - usedGb;
            if (e.desc) descriptions.push(e.desc);
        }
    }
    return { ramTotalMb, ramUsedMb, ramFreeMb, totalGb, usedGb, freeGb, descriptions };
}

function calcNetRate(deviceId, ifaces) {
    const result = [];
    for (const idx of Object.keys(ifaces).sort()) {
        const iface = ifaces[idx];
        const prevKey = 'net_prev_' + deviceId + '_' + idx;
        const prev = flow.get(prevKey) || { rx32: 0, tx32: 0, ts: Date.now() };
        const now = Date.now();
        const elapsed = (now - prev.ts) / 1000;
        let rxMbps = 0, txMbps = 0;
        if (elapsed > 0) {
            rxMbps = ((iface.rx32 - prev.rx32) * 8) / (elapsed * 1000000);
            txMbps = ((iface.tx32 - prev.tx32) * 8) / (elapsed * 1000000);
        }
        flow.set(prevKey, { rx32: iface.rx32, tx32: iface.tx32, ts: now });
        result.push({ name: iface.name || 'iface' + idx, rxMbps: Math.max(0, rxMbps), txMbps: Math.max(0, txMbps), rxErrors: iface.err, txErrors: 0, rxDrops: iface.drop, txDrops: 0, status: iface.status === 1 ? 'UP' : 'DOWN' });
    }
    return result;
}

const pool = global.get('pgPool');
