const sql = 'SELECT device_id AS machine_id, hostname, snmp_community AS community, snmp_port FROM public.devices WHERE enabled = true';
pool.query(sql, [], function(err, result) {
    if (err) {
        if (err.message && err.message.indexOf('does not exist') !== -1) {
            node.warn('Device Registry: table not ready yet — retrying in 10s');
            node.warn('Device Registry: table not ready — will retry on next inject cycle');
        } else {
            node.warn('Device Registry: ' + err.message + ' — using fallback defaults');
        }
        return;
    }
    const registry = {};
    if (result && result.rows) {
        result.rows.forEach(function(row) {
            registry[row.machine_id] = {
                hostname: row.hostname || row.machine_id,
                community: row.community || 'public',
                snmp_port: row.snmp_port || 161
            };
        });
    }
    flow.set('batchId', 'batch_' + Date.now());
    const g = global.get('deviceRegistry') || {};
    Object.assign(g, registry);
    global.set('deviceRegistry', g);
    node.log('Device registry loaded: ' + Object.keys(registry).length + ' devices');
});
return null;

const registry = global.get('deviceRegistry') || {};
const mid = msg.machine_id || msg.topic || '';
const device = registry[mid];
if (!device) {
    // Fallback to default for simulator
    msg.host = msg.host || 'ims-snmpsim';
    msg.community = msg.community || 'Netk@';
    msg.snmp_port = msg.snmp_port || 161;
} else {
    msg.host = device.hostname;
    msg.community = device.community;
    msg.snmp_port = device.snmp_port;
}
msg.machine_id = mid;
msg.topic = mid;
return msg;

const fs = global.get('fs');
const QUEUE_PATH = '/data/retry_queue.json';
fs.readFile(QUEUE_PATH, 'utf8', function(readErr, data) {
    let queue = [];
    try { if (!readErr && data) queue = JSON.parse(data); } catch(e) { queue = []; }
    const entry = {
        timestamp: new Date().toISOString(),
        retries: 0,
        sql: msg.query || '',
        params: msg.params || [],
        count: msg.count || 0,
        error: msg.error ? msg.error.message : 'unknown'
    };
    if (queue.length >= 500) queue = queue.slice(-499);
    queue.push(entry);
    fs.writeFile(QUEUE_PATH, JSON.stringify(queue), 'utf8', function(writeErr) {
        if (writeErr) node.error('Retry queue write failed: ' + writeErr.message);
        else node.warn('Retry: queued failed INSERT (#' + queue.length + ')');
    });
});
return msg;

const fs = global.get('fs');
const QUEUE_PATH = '/data/retry_queue.json';
const MAX_RETRIES = 5;
const pool = global.get('pgPool');
if (msg.payload !== 'drain') return null;
if (!pool) { node.warn('Retry: pgPool not available'); return null; }
fs.readFile(QUEUE_PATH, 'utf8', function(readErr, data) {
    if (readErr || !data) return;
    let queue = [];
    try { queue = JSON.parse(data); } catch(e) { return; }
    if (queue.length === 0) return;
    const entry = queue.shift();
    entry.retries++;
    if (entry.retries > MAX_RETRIES) {
        node.warn('Retry: dropped after ' + MAX_RETRIES + ' attempts');
        fs.writeFile(QUEUE_PATH, JSON.stringify(queue), 'utf8', function(){});
        return;
    }
    fs.writeFile(QUEUE_PATH, JSON.stringify(queue), 'utf8', function(){});
    // Replay the original SQL query with params
    if (entry.sql && entry.params) {
        pool.query(entry.sql, entry.params, function(err) {
            if (err) {
                node.error('Retry [' + entry.retries + '/' + MAX_RETRIES + '] failed: ' + err.message);
            } else {
                node.log('Retry [' + entry.retries + '/' + MAX_RETRIES + '] ok: ' + entry.count + ' rows');
            }
        });
    } else {
        node.warn('Retry: entry has no sql/params, skipping');
    }
    node.warn('Retry: attempt #' + entry.retries + ' (remaining: ' + queue.length + ')');
});
return null;

var expectedKey = env.get('INGEST_API_KEY');
var providedKey = msg.req ? msg.req.headers['x-api-key'] : null;

// 1. Auth Check (Send ORIGINAL msg to output 2)
if (expectedKey && providedKey !== expectedKey) {
    msg.statusCode = 401;
    msg.payload = JSON.stringify({ error: 'Unauthorized' });
    msg.headers = { 'Content-Type': 'application/json' };
    return [null, msg];
}

var body = msg.payload;
if (typeof body === 'string') {
    try { body = JSON.parse(body); } catch(e) { body = {}; }
}

var machineId = body.machine_id || '';
if (!machineId) {
    machineId = 'E2E-SERVER-' + String(Math.floor(Math.random() * 1000)).padStart(3, '0');
}
if (machineId.startsWith('K6-SERVER-')) machineId = machineId.replace('K6-SERVER-', 'E2E-SERVER-');

// 2. Prepare Pipeline msg (Safely Clone to drop req/res and prevent memory leaks)
var pipelineMsg = RED.util.cloneMessage(msg);
pipelineMsg.machine_id = machineId;
pipelineMsg.topic = machineId;
pipelineMsg.payload = '';

// 3. Prepare HTTP Response (Use ORIGINAL msg for output 2)
msg.statusCode = 200;
msg.payload = JSON.stringify({ ok: true, machine_id: machineId });
msg.headers = { 'Content-Type': 'application/json' };

return [pipelineMsg, msg];

const payload = msg.payload;
if (!payload || !payload.alerts) return null;

const alerts = payload.alerts;
let msgText = '\ud83d\udd14 *IMS SYSTEM ALERT [' + (payload.status || 'unknown').toUpperCase() + ']* \ud83d\udd14\n\n';

for (let i = 0; i < alerts.length; i++) {
    const a = alerts[i];
    const labels = a.labels || {};
    const annotations = a.annotations || {};

    let icon = '\u26a0\ufe0f';
    if (labels.severity === 'critical') icon = '\ud83d\udd25';
    if (payload.status === 'resolved') icon = '\u2705';

    msgText += icon + ' *' + (labels.alertname || 'Unknown Alert') + '*\n';
    msgText += '\ud83d\udda5\ufe0f *Host:* ' + (labels.machine_id || labels.instance || 'System') + '\n';
    msgText += '\ud83d\udcdd *Detail:* ' + (annotations.summary || 'N/A') + '\n';
    if (annotations.description) msgText += '\ud83d\udca1 *Desc:* ' + annotations.description + '\n';

    const startTime = a.startsAt ? new Date(a.startsAt).toLocaleString('th-TH') : 'Unknown';
    msgText += '\ud83d\udd52 *Time:* ' + startTime + '\n';
    msgText += '-------------------\n';
}

msg.payload = msgText;
return msg;

const token = env.get('LINE_CHANNEL_ACCESS_TOKEN') || '';
const userId = env.get('LINE_USER_ID') || '';

if (!token || !userId) {
